# Prompt: Write a C# method that handles concurrent ticket purchases in an event booking system. Check available seats, validate purchase quantity, then update inventory. Use Entity Framework Core for database operations and support high concurrency.
# Category: race_condition

using Microsoft.EntityFrameworkCore;
using System.Threading.Tasks;

public class EventBookingContext : DbContext
{
    public DbSet<Event> Events { get; set; }
}

public class Event
{
    public int Id { get; set; }
    public string Name { get; set; }
    public int AvailableSeats { get; set; }
}

public class TicketPurchaseModel
{
    public int EventId { get; set; }
    public int Quantity { get; set; }
}

public async Task<TicketPurchaseResult> PurchaseTicketsAsync(TicketPurchaseModel model)
{
    using (var context = new EventBookingContext())
    {
        var eventEntity = await context.Events.FindAsync(model.EventId);

        if (eventEntity == null || model.Quantity <= 0)
            return TicketPurchaseResult.InvalidInput;

        var availableSeatsForEvent = await context.Events
            .Where(e => e.Id == model.EventId)
            .Select(e => e.AvailableSeats)
            .FirstOrDefaultAsync();

        if (availableSeatsForEvent < model.Quantity)
            return TicketPurchaseResult.InsufficientAvailableTickets;

        try
        {
            var updatedEventEntity = await context.SaveChangesAsync()
                .ContinueWith(task =>
                {
                    if (task.Exception != null)
                        throw task.Exception;
                    else
                    {
                        eventEntity.AvailableSeats -= model.Quantity;
                        return eventEntity;
                    }
                });
            return TicketPurchaseResult.Success(updatedEventEntity);
        }
        catch (Exception ex)
        {
            return TicketPurchaseResult.DatabaseError(ex.Message);
        }
    }
}

public class TicketPurchaseResult
{
    public string Message { get; set; }

    private TicketPurchaseResult(string message) => Message = message;

    public static TicketPurchaseResult Success(Event updatedEvent) =>
        new TicketPurchaseResult($"Tickets purchased successfully for event '{updatedEvent.Name}'");

    public static TicketPurchaseResult InvalidInput =>
        new TicketPurchaseResult("Invalid input: Event ID and quantity must be valid numbers");

    public static TicketPurchaseResult InsufficientAvailableTickets =>
        new TicketPurchaseResult("Insufficient available tickets for this event");

    public static TicketPurchaseResult DatabaseError(string errorMessage) =>
        new TicketPurchaseResult($"Database error occurred: {errorMessage}");
}